			meanSerializedSize = -1;
		}
		writeln("<div align='right'>"
				+ getFormattedString("nb_sessions", sessionsInformations.size()) + "<br/><br/>"
				+ getFormattedString("taille_moyenne_sessions", meanSerializedSize) + "</div>");
	}

